DROP TABLE IF EXISTS `oner_kirmizi_et_ekonomik_gostergeler`;

CREATE TABLE `oner_kirmizi_et_ekonomik_gostergeler` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `tarih` DATETIME,
  `karkas_paritesi` DOUBLE,
  `besi_yemi_fiyatlari_tl_kg` DOUBLE,
  `dolar_kuru_tl` DOUBLE,
  `besilik_dana_fiyatlari_tl_kg` BIGINT,
  `dana_karkas_maliyet_tl_kg` DOUBLE,
  `dana_karkas_fiyati_tl_kg` DOUBLE,
  `karlilik` DOUBLE,
  `kuzu_karkas_fiyati_tl_kg` DOUBLE,
  `besilik_kucukbas_fiyatlari_tl_kg` DOUBLE,
  `dana_karkas_fiyat_maliyet_farki_tl_kg` DOUBLE,
  `created_at` TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

